export interface BoardGame {
  id: string;
  bggId?: string; // BoardGameGeek ID
  imageUrl: string;
  koreanName: string;
  englishName: string;
  recommendedPlayers: string;
  playTime: string;
  difficulty: string;
  videoUrl: string;
  rating?: number; // 1-10 평점
  playRecords?: PlayRecord[];
  // 추가 체크 항목
  hasSleeve?: boolean; // 슬리브 완료
  hasStorage?: boolean; // 박스 아스테이지 완료
  hasComponentUpgrade?: boolean; // 컴포 업그레이드
  boxCondition?: 'S' | 'A' | 'B' | 'C'; // 박스 상태
  languageEdition?: 'korean' | 'english' | 'multilingual'; // 언어판 (한글판/영문판/다국어판)
  quantity?: number; // 보유 수량 (기본값 1)
  playCount?: number; // 플레이 횟수
  // 확장판 관련
  isExpansion?: boolean; // 확장판 여부
  expansionType?: 'expansion' | 'series' | 'legacy'; // 확장 종류
  parentGameId?: string; // 본판 게임 ID (확장판인 경우)
  createdAt?: string; // 게임 추가 시간 (ISO 8601 형식)
  // 보드위키 카테고리
  wikiCategories?: {
    mechanisms?: string[]; // 메커니즘 (타일 배치, 손 관리, 워커 플레이스먼트 등)
    themes?: string[]; //  (판타지, 중세, SF 등)
    languageDependence?: string; // 언어 의존도
    gameType?: string; // 게임 종류
  };
  wikiInfo?: string; // 위키 정보 (사용자가 작성)
  isReleasing?: boolean; // 방출 예정 (마켓 미등록)
  purchaseDate?: string; // 구매 시기 (YYYY-MM-DD)
  purchasePrice?: number; // 구매 금액
}

export interface PlayRecord {
  id: string;
  date: string;
  memo?: string; // 선택 항목으로 변경
  // 플레이어 정보
  players: {
    name: string;
    score: number;
  }[];
  winner: string; // 플레이어 이름 또는 "무승부" 또는 "승자 없음"
  // 플레이 시간 (분 단위)
  totalTime: number;
  // 사용한 확장판 ID 목록
  expansionsUsed: string[];
  // 게임 장소
  location?: string;
  // 사진 URL 목록
  images?: string[];
  // 인원별 별점 (플레이 인원 수에 대한 평가)
  playerCountRating?: number; // 1-10
  // 작성자
  createdBy?: string;
  createdAt?: string;
}

